public class OnboardingTraining : TrainingContentBase
{
    public OnboardingTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Welcome to QB Engineer",
            Slug = "welcome-to-forge",
            Summary = "Get oriented with QB Engineer — what it does, how it's organized, and what you'll use every day.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 3,
            IsPublished = true,
            IsOnboardingRequired = true,
            SortOrder = 1,
            AppRoutes = """["/dashboard"]""",
            Tags = """["onboarding","welcome"]""",
            ContentJson = """{"body":"## Welcome to QB Engineer\n\nQB Engineer is a manufacturing operations platform built for small engineering shops. It connects every part of your workflow — from quoting a job to shipping it — in one unified system. You'll use it every day for tracking work, logging time, submitting expenses, and staying compliant.\n\n### What It Does\n\nAt its core, QB Engineer manages jobs on a kanban board. Every job moves through stages from Quote Requested all the way to Payment Received, matching how work actually flows through a machine shop. Along the way it integrates with QuickBooks Online to keep your financials in sync automatically.\n\nBeyond jobs, QB Engineer handles parts catalogs (including BOMs), inventory, purchase orders, sales orders, shipments, and quality inspections. Everything is connected — a job links to a part, which links to its BOM, which links to the vendor POs.\n\n### How It's Organized\n\nThe left sidebar is your primary navigation. Icons expand to labeled sections when you hover. The main areas you'll use:\n\n- **Dashboard** — your daily summary: open jobs, tasks, timers, cycle progress\n- **Board** — the kanban board for all active jobs\n- **Time Tracking** — start/stop timers and review your logged hours\n- **Account** — your profile, compliance forms, pay stubs, and security settings\n\n### What to Do Next\n\nStart by completing the remaining modules in this onboarding path. They'll walk you through setting up your profile, completing required compliance forms, logging time, and submitting expenses. The whole path takes about 25 minutes.\n\nAfter onboarding, your manager will assign additional training paths based on your role.","sections":[]}"""
        });

        await GetOrCreateModule(new TrainingModule
        {
            Title = "Setting Up Your Profile",
            Slug = "setting-up-your-profile",
            Summary = "How to complete your contact info, emergency contact, and account security settings.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            IsOnboardingRequired = true,
            SortOrder = 3,
            AppRoutes = """["/account","/account/profile"]""",
            Tags = """["onboarding","account"]""",
            ContentJson = """{"body":"## Setting Up Your Profile\n\nYour employee profile is how the system knows who you are, where to reach you, and how to pay you. Completing it accurately is important — your work location drives which state withholding forms you'll need to fill out.\n\n### Profile Section\n\nNavigate to **Account → Profile**. Fill in your first and last name, then confirm your work location. If you work at a location other than the company's default, update this now — it affects your state tax withholding.\n\n### Contact Information\n\nGo to **Account → Contact**. Enter your personal phone number and home address. This is kept confidential and is only used for HR and payroll purposes.\n\n### Emergency Contact\n\nUnder **Account → Emergency**, add the name, phone number, and relationship of someone to contact in an emergency. This is required as part of your onboarding.\n\n### Security Settings\n\nVisit **Account → Security** to review your login settings. If your employer uses badge/PIN kiosk login, you'll use the 4–8 digit PIN you were assigned. You can change this PIN here at any time.\n\n### Why It Matters\n\nYour profile drives your compliance form requirements. An incomplete work location means the system can't determine which state withholding form to show you. An incomplete address or emergency contact will show a yellow warning on your profile completeness tracker.","sections":[]}"""
        });

        await GetOrCreateModule(new TrainingModule
        {
            Title = "Onboarding Knowledge Check",
            Slug = "onboarding-quiz",
            Summary = "A short quiz to confirm you're ready to work in QB Engineer.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            IsOnboardingRequired = true,
            SortOrder = 7,
            AppRoutes = """["/training"]""",
            Tags = """["onboarding","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":10,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"ob1","text":"Where do you go to start a work timer for a specific job?","options":[{"id":"a","text":"The Reports page — it tracks all job activity"},{"id":"b","text":"The job card on the Kanban Board or the Time Tracking page","isCorrect":true},{"id":"c","text":"The Admin panel under Time Settings"},{"id":"d","text":"The Backlog — select the job and click Start"}],"explanation":"Timers can be started from the job card on the Kanban Board or from the Time Tracking page. Both give you a running clock tied to that specific job."},{"id":"ob2","text":"You forgot to start your timer this morning. How do you record those hours?","options":[{"id":"a","text":"Ask your manager to add them to your timesheet"},{"id":"b","text":"You can't — only real-time timers are allowed"},{"id":"c","text":"Add a manual time entry in the Time Tracking page","isCorrect":true},{"id":"d","text":"Edit the job description to note the time worked"}],"explanation":"The Time Tracking page supports manual entries for cases when you forgot to start a timer. Enter the date, job, and duration directly."},{"id":"ob3","text":"Which section shows all your required compliance forms (W-4, I-9, etc.)?","options":[{"id":"a","text":"Account → Tax Forms","isCorrect":true},{"id":"b","text":"Admin → Compliance Templates"},{"id":"c","text":"Dashboard → Getting Started"},{"id":"d","text":"Reports → Employee Documents"}],"explanation":"All personal tax and compliance forms live under Account → Tax Forms. You'll see your submission status and any forms that still need to be completed."},{"id":"ob4","text":"You need to submit a $45 fuel expense for a job site visit. What should you do?","options":[{"id":"a","text":"Email your manager the receipt and they'll enter it"},{"id":"b","text":"Go to Expenses, click New Expense, fill in the details, upload your receipt, and submit","isCorrect":true},{"id":"c","text":"Add a note to the job card with the dollar amount"},{"id":"d","text":"Log it as billable time since you were traveling"}],"explanation":"All expense reimbursements go through the Expenses page. Upload your receipt, select the category, link it to a job if applicable, and submit for approval."},{"id":"ob5","text":"Where do you update your emergency contact information?","options":[{"id":"a","text":"Account → Emergency","isCorrect":true},{"id":"b","text":"Admin → Users → your profile"},{"id":"c","text":"Dashboard → Profile card"},{"id":"d","text":"Account → Security"}],"explanation":"Emergency contacts are managed under Account → Emergency. Keep this up to date — it's required for onboarding completion."},{"id":"ob6","text":"You want to see how complete your employee profile is. Where do you look?","options":[{"id":"a","text":"Dashboard → Profile Completeness widget","isCorrect":true},{"id":"b","text":"Admin → Users → your account"},{"id":"c","text":"Reports → Employee Status"},{"id":"d","text":"Account → Security → Profile Score"}],"explanation":"The Dashboard shows a Profile Completeness widget that lists exactly which items are still missing. It disappears once you've finished all required sections."},{"id":"ob7","text":"You want to change your login password. Where do you go?","options":[{"id":"a","text":"Admin → Users — your admin can reset it"},{"id":"b","text":"Account → Security","isCorrect":true},{"id":"c","text":"Dashboard → Settings → Password"},{"id":"d","text":"Account → Profile → Edit"}],"explanation":"Your password and authentication settings are under Account → Security. You can update your password there at any time without contacting an admin."},{"id":"ob8","text":"A notification badge appears on the bell icon in the header. What does that indicate?","options":[{"id":"a","text":"You have a new message in the Chat feature"},{"id":"b","text":"Your session is about to expire"},{"id":"c","text":"You have unread notifications from the system or your teammates","isCorrect":true},{"id":"d","text":"A compliance form is overdue — the badge always means that"}],"explanation":"The bell badge shows the count of unread notifications. Click it to open the notification panel where you can see, dismiss, and pin individual notifications."},{"id":"ob9","text":"You need to attach a PDF drawing to a job. Where in the job is the best place to do this?","options":[{"id":"a","text":"Job detail panel → Files section (drag and drop or click to browse)","isCorrect":true},{"id":"b","text":"Parts Catalog → attach it to the related part instead"},{"id":"c","text":"Reports → upload to a saved report"},{"id":"d","text":"Admin → Document Storage"}],"explanation":"The job detail panel has a Files section where you can attach PDFs, images, CAD files, and other documents directly to the job record."},{"id":"ob10","text":"What happens to a job when it is archived?","options":[{"id":"a","text":"It is permanently deleted from the system"},{"id":"b","text":"It moves to a separate archive database that admins can access"},{"id":"c","text":"It is removed from the board but preserved in the system for reporting and traceability","isCorrect":true},{"id":"d","text":"It is locked and no further changes can be made"}],"explanation":"Jobs are never deleted in QB Engineer — they're archived. An archived job disappears from the board but remains fully searchable and visible in the Backlog with the Archived filter."},{"id":"ob11","text":"Where would you find jobs assigned to you that are due today?","options":[{"id":"a","text":"Reports → My Jobs Due Today"},{"id":"b","text":"Dashboard → Today's Tasks widget","isCorrect":true},{"id":"c","text":"Backlog → filter by assignee and due date"},{"id":"d","text":"Kanban Board → scroll to find your cards"}],"explanation":"The Today's Tasks widget on the Dashboard shows all active jobs assigned to you, sorted by due date, with overdue jobs highlighted."},{"id":"ob12","text":"You started a timer on the wrong job. What should you do?","options":[{"id":"a","text":"Let it run — you can't stop a timer once started"},{"id":"b","text":"Stop the timer, then manually edit the time entry to correct the job","isCorrect":true},{"id":"c","text":"Ask your manager to delete it"},{"id":"d","text":"Archive the job and start again"}],"explanation":"Stop the running timer, then go to Time Tracking to edit the entry — you can correct the linked job, adjust the duration, or delete it entirely."},{"id":"ob13","text":"Which page shows all open purchase orders for materials your team is waiting on?","options":[{"id":"a","text":"Inventory → Pending Receipts"},{"id":"b","text":"Backlog → filter by status Materials Ordered"},{"id":"c","text":"Purchase Orders page","isCorrect":true},{"id":"d","text":"Dashboard → Open Orders widget shows all POs"}],"explanation":"The Purchase Orders page lists all POs with their status (Draft, Sent, Partially Received, Received). You can see what's outstanding and when deliveries are expected."},{"id":"ob14","text":"You want to send a message to a coworker about a specific job without leaving the app. What do you use?","options":[{"id":"a","text":"Email them from your regular email client"},{"id":"b","text":"Add a note to the job card and @mention them","isCorrect":true},{"id":"c","text":"Update the job description and hope they notice"},{"id":"d","text":"Use the Reports page to flag the job for review"}],"explanation":"Typing a comment in the job's activity feed and @mentioning a teammate sends them an in-app notification. They can reply directly on the job card."},{"id":"ob15","text":"Your W-4 was recently updated and you need to re-submit it. Where do you go?","options":[{"id":"a","text":"Admin → Compliance → re-upload"},{"id":"b","text":"Account → Tax Forms — find the W-4 and click to complete it again","isCorrect":true},{"id":"c","text":"Reports → Employee → Tax Documents"},{"id":"d","text":"Contact payroll — you cannot self-submit"}],"explanation":"Account → Tax Forms lets you view and re-submit compliance forms like the W-4 whenever they need to be updated. Your submission history is also visible there."},{"id":"ob16","text":"The Kanban board shows a column with a red header. What does this indicate?","options":[{"id":"a","text":"The column contains at least one overdue job"},{"id":"b","text":"The column has been locked by an admin"},{"id":"c","text":"The job count in that column has exceeded the WIP limit","isCorrect":true},{"id":"d","text":"The column contains jobs with Critical priority"}],"explanation":"Column headers turn red when the number of jobs exceeds the configured WIP (Work In Progress) limit. It's a visual signal to finish work before adding more to that stage."},{"id":"ob17","text":"You want to see everything that happened to a specific job — who moved it, what changed, what notes were added. Where is this?","options":[{"id":"a","text":"Reports → Job History"},{"id":"b","text":"Job detail panel → Activity tab","isCorrect":true},{"id":"c","text":"Admin → Audit Log — filter by job"},{"id":"d","text":"Backlog → job row → expand"}],"explanation":"Every job has a full activity timeline in its detail panel. It shows stage moves, field edits, file uploads, comments, @mentions, and timer starts/stops in chronological order."},{"id":"ob18","text":"Where do you go to view your recent pay stubs?","options":[{"id":"a","text":"Dashboard → Payroll widget"},{"id":"b","text":"Admin → Payroll → your records"},{"id":"c","text":"Account → Pay Stubs","isCorrect":true},{"id":"d","text":"Reports → Payroll → filter by employee"}],"explanation":"Your personal pay stubs are available under Account → Pay Stubs. Admins upload pay stubs there and you receive a notification when a new one is available."},{"id":"ob19","text":"What is the correct way to log time on a job you finished yesterday but forgot to track?","options":[{"id":"a","text":"You cannot log time for a previous date — only today"},{"id":"b","text":"Ask your manager to enter it in the system for you"},{"id":"c","text":"Open Time Tracking, click New Entry, set yesterday's date, and enter the duration","isCorrect":true},{"id":"d","text":"Add a comment to the job explaining the hours worked"}],"explanation":"Manual time entries support any past date. Open Time Tracking → New Entry, select the correct date and job, enter the hours, and save."},{"id":"ob20","text":"You want to print a barcode label for a job. Where do you do this?","options":[{"id":"a","text":"Reports → Labels → generate from job list"},{"id":"b","text":"Job detail panel → print a label from the job's action menu","isCorrect":true},{"id":"c","text":"Admin → Label Templates → select and print"},{"id":"d","text":"Inventory → Bin Labels — all labels are printed from there"}],"explanation":"Job labels are printed directly from the job detail panel. The label includes the job number, QR code, and barcode for use with shop floor scanners."}]}"""
        });

        // ── New-Hire Onboarding Wizard (Article) ─────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "New-Hire Onboarding Wizard",
            Slug = "onboarding-wizard-overview",
            Summary = "The 7-step new-hire paperwork wizard at /onboarding: Personal, Address, W-4, State Withholding, I-9, Direct Deposit, and Acknowledgments — what each step collects and how progress is saved.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 6,
            IsPublished = true,
            IsOnboardingRequired = true,
            SortOrder = 4,
            AppRoutes = """["/onboarding"]""",
            Tags = """["onboarding","wizard","paperwork","i9","w4"]""",
            ContentJson = """{"body":"## New-Hire Onboarding Wizard\n\nWhen you first sign in as a new employee, QB Engineer takes you to the onboarding wizard at **/onboarding**. This is a single guided form that collects all the standard new-hire paperwork in one place — the same documents you'd fill out on paper your first day, but typed once and reused everywhere. It has **seven steps**, shown as a numbered stepper bar across the top.\n\n### How the wizard works\n\n- **One step at a time.** Each step is a focused form. The **Continue** button at the bottom-right advances you; **Back** returns to the previous step. You can also click a completed step number in the bar to jump back to it.\n- **You can't skip ahead past unfinished work.** Continue stays disabled until the current step's required fields are valid. A small warning icon next to the button lists exactly what's missing — click it to see the list.\n- **The URL tracks your step** (`/onboarding?step=0` through `?step=6`). Refreshing the page or coming back later returns you to where you left off — your answers are saved to a secure server-side draft as you go, not just in the browser.\n- **Sensitive values are stored securely.** Your Social Security Number, bank routing/account numbers, and I-9 document numbers are encrypted. When you return to a step that already has one saved, you'll see a **\"Securely stored\"** lock note instead of the value — leave the field blank to keep what's saved, or type a new value to overwrite it.\n\n### The seven steps\n\n**1. Personal Information** — Your legal first/middle/last name, any other last names used, date of birth, Social Security Number, email, and phone. Name and email may already be filled in from your account.\n\n**2. Home Address** — Street, city, state, and ZIP. Your **state** here matters: it determines whether Step 4 (State Withholding) applies to you.\n\n**3. Federal Tax Withholding (W-4)** — Your IRS Form W-4 elections: filing status, the multiple-jobs checkbox, dependents (the wizard multiplies qualifying children × $2,000 and other dependents × $500 and shows you the running credit total), optional other-income/deductions/extra-withholding adjustments, and an exempt-from-withholding toggle.\n\n**4. State Withholding** — Your state's equivalent of the W-4. If you live in a **state with no income tax** (Alaska, Florida, Nevada, South Dakota, Tennessee, Texas, Washington, Wyoming), the wizard detects this from your Step 2 address and shows a green \"nothing to do here\" notice — you just continue. Otherwise you set your state filing status, allowances, any additional withholding, and an exempt toggle.\n\n**5. I-9 Employment Eligibility** — Federal Form I-9 Section 1. You attest to your citizenship/work-authorization status, then prove your identity and work authorization by providing **either one List A document** (e.g., U.S. Passport — proves both identity and authorization) **or one List B + one List C document** (e.g., Driver's License + Social Security Card). For each document you pick the type, enter the document number and issuing authority, optionally an expiration date, and **upload a photo or PDF** of it. A preparer/translator section is available if someone helped you complete the form.\n\n**6. Direct Deposit** — Your bank name, 9-digit routing number, account number, and account type (Checking or Savings) so payroll can pay you electronically. A small check diagram shows where to find the routing and account numbers.\n\n**7. Acknowledgments** — You confirm you've reviewed the required policies. The **Workers' Compensation** acknowledgment is always required; an **Employee Handbook** acknowledgment appears only if your employer has uploaded a handbook. Each shows a link to the document, then a toggle to confirm.\n\n### Finishing: Submit & Sign\n\nThe final button is **Submit & Sign**. It saves all your data, then moves you into the review-and-sign flow where you preview each filled-out form (W-4, I-9, state form) and e-sign it. See the **Review & E-Sign Your Forms** module for that part. Once every form is signed, you land on a completion screen with a button to go to your dashboard.\n\n### If you need to stop\n\nYou don't have to finish in one sitting. Because your progress is saved server-side after each step, you can close the tab and come back — even on a different device — and pick up where you left off. Nothing is final until you submit and sign.","sections":[]}"""
        });

        // ── New-Hire Onboarding Wizard (Walkthrough) ─────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "New-Hire Onboarding Wizard — Guided Tour",
            Slug = "onboarding-wizard-walkthrough",
            Summary = "A guided tour of the onboarding wizard: the step bar, the first step's fields, the securely-stored indicator, and the Continue / Submit & Sign actions.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 4,
            IsPublished = true,
            IsOnboardingRequired = true,
            SortOrder = 5,
            AppRoutes = """["/onboarding"]""",
            Tags = """["onboarding","wizard","walkthrough"]""",
            ContentJson = """{"appRoute":"/onboarding","startButtonLabel":"Tour the Wizard","steps":[{"element":".onboarding__header","popover":{"title":"New-Hire Onboarding","description":"This is the onboarding wizard. It collects all your standard new-hire paperwork — personal info, tax forms (W-4 and state), I-9 employment eligibility, direct deposit, and policy acknowledgments — in one guided flow. You only type each thing once.","side":"bottom"}},{"element":".onboarding__stepper","popover":{"title":"The Seven Steps","description":"The numbered bar across the top shows all seven steps: Personal, Address, Federal Tax (W-4), State Tax, I-9, Direct Deposit, and Acknowledgments. The highlighted step is where you are now. Once you've completed a step you can click its number to jump back and edit it.","side":"bottom"}},{"element":".step-content","popover":{"title":"One Step at a Time","description":"Each step is a focused form. Fill in the fields, then use Continue to move forward. Your answers are saved to a secure server-side draft as you go — if you close the tab and come back later, even on another device, you'll return right here.","side":"top"}},{"element":"[data-testid='onboarding-ssn']","popover":{"title":"Securely Stored Fields","description":"Sensitive values like your Social Security Number, bank numbers, and I-9 document numbers are encrypted. When you return to a step that already has one saved, you'll see a 'Securely stored' lock note — leave the field blank to keep it, or type a new value to overwrite it.","side":"top"}},{"element":".onboarding__actions","popover":{"title":"Continue — and Submit & Sign","description":"Continue advances to the next step; it stays disabled until the current step's required fields are valid (the warning icon lists what's missing). On the last step, this becomes 'Submit & Sign', which saves everything and moves you into the review-and-sign flow for your tax and I-9 forms.","side":"top"}}]}"""
        });

        // ── Review & E-Sign Your Forms (Article) ─────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Review & E-Sign Your Forms",
            Slug = "onboarding-review-esign",
            Summary = "After submitting the onboarding wizard, review each pre-filled form (W-4, I-9, state withholding) as a PDF and e-sign it. How the per-form preview → sign loop works and how to fix a mistake before signing.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            IsOnboardingRequired = true,
            SortOrder = 6,
            AppRoutes = """["/onboarding"]""",
            Tags = """["onboarding","esign","docuseal","w4","i9"]""",
            ContentJson = """{"body":"## Review & E-Sign Your Forms\n\nWhen you click **Submit & Sign** on the last step of the onboarding wizard, QB Engineer saves all your data and then walks you through reviewing and electronically signing each official form your entries produced — typically your **W-4**, your **state withholding form**, and your **I-9**. You sign them one at a time.\n\n### The progress strip\n\nAt the top of this screen is a row of form names with status icons — one per form you need to sign. The form you're currently on is highlighted, finished forms get a check mark, and forms still ahead show an empty circle. This is your map through the signing flow.\n\n### Step 1 — Preview the filled form\n\nFor each form, the wizard first shows you a **preview**: the actual government PDF, filled in with the answers you typed in the wizard, rendered right in the browser. Read it over. Everything in it came from your wizard entries — this is your chance to catch a typo before it's on a signed document.\n\nIf a form doesn't have a PDF template configured, you'll instead see a short **summary** of the key values (for example, your W-4 filing status, or your I-9 citizenship selection and which documents you provided) so you can still confirm them before signing.\n\n### Found a mistake? Go back to edit\n\nIf the preview is wrong, click **Go Back to Edit**. That drops you out of the signing flow and back into the wizard so you can correct it. (You'll land on the Acknowledgments step; from there use the wizard's Back button to reach the W-4, I-9, or state step you need to change.) Then submit again — the preview regenerates from your corrected answers.\n\n### Step 2 — Sign\n\nWhen the preview looks right, click **Sign Form**. The wizard loads a secure signing session (powered by DocuSeal, embedded in the page) where you apply your signature. When you complete the signature, the wizard automatically marks that form done and advances to the next one — back to a preview, then sign, and so on.\n\nWhile you're in the signing view you can click **Back to Preview** to look at the filled PDF again before committing.\n\n### Finishing up\n\nAfter you sign the last form, you reach the **completion screen** — a confirmation that onboarding is done, with a button to go to your dashboard. Your signed forms are stored on your record; an admin or manager can complete any employer-side portions (such as I-9 Section 2) afterward.\n\n### If you get interrupted\n\nThe signing flow remembers where you are. If you refresh the page or close the tab mid-signing, you'll be returned to the same form and phase (preview or signing) rather than back to the start of the wizard — so you never have to redo signatures you've already completed.","sections":[]}"""
        });

        // ── Onboarding Wizard Knowledge Check (Quiz) ─────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Onboarding Wizard Knowledge Check",
            Slug = "onboarding-wizard-quiz",
            Summary = "Test your understanding of the new-hire onboarding wizard: the seven steps, the W-4 and I-9, securely-stored fields, saving progress, and the review-and-sign flow.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            IsOnboardingRequired = true,
            SortOrder = 7,
            AppRoutes = """["/onboarding"]""",
            Tags = """["onboarding","wizard","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"ow1","text":"How many steps does the new-hire onboarding wizard have, and how do you move through them?","options":[{"id":"a","text":"Seven steps; use the Continue button (or click a completed step number) to advance, Back to return","isCorrect":true},{"id":"b","text":"Three steps, all on a single scrolling page"},{"id":"c","text":"Seven steps, but you must complete them in a single sitting with no way to go back"},{"id":"d","text":"As many steps as your role requires — it varies per user"}],"explanation":"The wizard has seven steps shown in a numbered stepper bar: Personal, Address, W-4, State Withholding, I-9, Direct Deposit, and Acknowledgments. Continue advances you, Back returns, and you can click a completed step number to jump back and edit it."},{"id":"ow2","text":"You return to the onboarding wizard the next day. What do you find?","options":[{"id":"a","text":"You have to start over — onboarding can't be paused"},{"id":"b","text":"Your progress is restored from a secure server-side draft, returning you to where you left off","isCorrect":true},{"id":"c","text":"Only the steps you completed in the browser session are kept; anything else is lost"},{"id":"d","text":"A manager must re-enable the wizard before you can continue"}],"explanation":"The wizard saves your answers to a secure server-side draft as you complete each step, and the URL tracks your step. You can close the tab and come back — even on a different device — and resume right where you stopped. Nothing is final until you submit and sign."},{"id":"ow3","text":"You return to the Personal step and the SSN field is blank with a 'Securely stored' lock note. What does this mean and what should you do?","options":[{"id":"a","text":"Your SSN was lost and you must re-enter it"},{"id":"b","text":"Your SSN is already saved and encrypted — leave the field blank to keep it, or type a new value only if you need to overwrite it","isCorrect":true},{"id":"c","text":"The field is broken and you should contact an admin"},{"id":"d","text":"You must re-enter the SSN every time you visit the step"}],"explanation":"Sensitive values (SSN, bank routing/account numbers, I-9 document numbers) are encrypted and never sent back to the browser. The 'Securely stored' indicator means a value is already saved. Leave the field blank to keep it; type a new value only to overwrite."},{"id":"ow4","text":"On the State Withholding step you see a green notice saying there's nothing to fill out. Why?","options":[{"id":"a","text":"Your employer disabled state withholding for all employees"},{"id":"b","text":"The address you entered is in a state with no income tax, so no state withholding form is needed","isCorrect":true},{"id":"c","text":"You already completed the federal W-4, which replaces the state form"},{"id":"d","text":"State withholding is only required for managers"}],"explanation":"The wizard reads the state from your Step 2 address. For the no-income-tax states (Alaska, Florida, Nevada, South Dakota, Tennessee, Texas, Washington, Wyoming) there's no state withholding form, so it shows a green notice and you simply continue."},{"id":"ow5","text":"On the I-9 step, how do you prove your identity and work authorization?","options":[{"id":"a","text":"Provide your SSN only — no documents are needed"},{"id":"b","text":"Provide either one List A document, OR one List B document plus one List C document — and upload a photo/PDF of each","isCorrect":true},{"id":"c","text":"Upload three documents from any list"},{"id":"d","text":"Documents are collected later by HR; the wizard only records your name"}],"explanation":"Form I-9 requires either a single List A document (which proves both identity and work authorization, e.g., a U.S. Passport) or the combination of one List B document (identity, e.g., a driver's license) and one List C document (work authorization, e.g., a Social Security card). For each, you pick the type, enter the details, and upload an image or PDF."},{"id":"ow6","text":"On the W-4 step you enter 2 qualifying children and 1 other dependent. What does the wizard show you?","options":[{"id":"a","text":"Nothing — the W-4 doesn't calculate anything"},{"id":"b","text":"A running credit total: 2 × $2,000 plus 1 × $500 = $4,500","isCorrect":true},{"id":"c","text":"A warning that you've claimed too many dependents"},{"id":"d","text":"It multiplies every dependent by $2,000 regardless of type"}],"explanation":"The W-4 step computes the dependent credit the way the IRS form does: qualifying children are multiplied by $2,000 and other dependents by $500, and the wizard displays the running total ($4,500 in this example) so you can see the result of your entries."},{"id":"ow7","text":"After clicking Submit & Sign, what happens next?","options":[{"id":"a","text":"Onboarding is immediately complete with no further action"},{"id":"b","text":"You enter a review-and-sign flow where you preview each filled-out form as a PDF and e-sign it, one at a time","isCorrect":true},{"id":"c","text":"The forms are emailed to you to print, sign by hand, and mail back"},{"id":"d","text":"A manager signs the forms on your behalf"}],"explanation":"Submit & Sign saves your data and moves you into the per-form review-and-sign flow. For each form (typically W-4, state withholding, and I-9) you preview the pre-filled PDF, then e-sign it via the embedded signing session. After the last form is signed you reach the completion screen."},{"id":"ow8","text":"While previewing your filled-out W-4 before signing, you spot a wrong filing status. What's the right move?","options":[{"id":"a","text":"Sign it anyway and ask payroll to fix it later"},{"id":"b","text":"Click 'Go Back to Edit' to return to the wizard, correct the entry, then submit again to regenerate the preview","isCorrect":true},{"id":"c","text":"There's no way to fix it once you've reached the preview"},{"id":"d","text":"Delete your whole onboarding draft and start from scratch"}],"explanation":"The preview is specifically your chance to catch mistakes before signing. 'Go Back to Edit' drops you out of the signing flow and back into the wizard so you can correct the field, then submitting again regenerates the preview from your corrected answers."}]}"""
